static void kb_buffer_add(char c) {
    uint16_t next_write = (kb_buffer_write + 1) % KB_BUFFER_SIZE;
    if (next_write != kb_buffer_read) {
        kb_buffer[kb_buffer_write] = c;
        kb_buffer_write = next_write;
    }
}

